from Cryptodome import Cipher, PKCS12
from Cryptodome.Random import get_random_bytes
import base64

def load_key(password):
    with open('app_config.p12', 'rb') as f:
        pkcs12 = PKCS12.load(f, password=password.encode())
    return pkcs12['private_key']

def encrypt_card_number(key, card_number):
    iv = get_random_bytes(16)
    cipher = Cipher.new(key, Cipher.MODE_CBC, iv)
    encrypted = base64.b64encode(iv + cipher.encrypt(card_number))
    return iv.hex() + ':' + encrypted.decode('ascii')

def decrypt_card_number(key, encrypted_data):
    iv, encrypted = encrypted_data.split(':')
    iv = bytes.fromhex(iv)
    cipher = Cipher.new(key, Cipher.MODE_CBC, iv)
    return base64.b64decode(base64.b64decode(encrypted)[:-16])  # remove IV from encrypted data before decryption